#define HEADER_SIZE 10

typedef struct {
    char key[50];
    char value[100];
} HeaderEntry;

typedef struct {
    HeaderEntry entries[HEADER_SIZE];
    int count;
} HeaderDict;
// ਹੈਡਰ ਡਿਕਸ਼ਨਰੀ ਵਿੱਚ ਕੁੰਜੀ ਦਾ ਇੰਡੈਕਸ ਲੱਭਣ ਲਈ ਫੰਕਸ਼ਨ, ਜੇ ਨਾ ਮਿਲੇ ਤਾਂ -1 ਵਾਪਸ ਕਰਦਾ ਹੈint find_header_index(const HeaderDict *header, const char *key) {
    for (int i = 0; i < header->count; i++) {
        if (strcmp(header->entries[i].key, key) == 0) {
            return i;
        }
    }
    return -1;
}

